import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ShoppingBag, Mail, Lock, Eye, EyeOff, Smartphone, KeyRound, ArrowRight } from 'lucide-react';
import { mongoAuthAPI, getUserIdFromToken } from '../api';
import { formatTime } from '../utils/helpers';

const LoginPage = ({ 
  setCurrentPage, 
  setUser, 
  setError, 
  error, 
  loading, 
  setLoading 
}) => {
  const [showPassword, setShowPassword] = useState(false);
  const [loginData, setLoginData] = useState({ email: '', password: '' });
  const [loginRole, setLoginRole] = useState('Customer');
  const [loginMethod, setLoginMethod] = useState('email');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '', '', '']);
  const [otpSent, setOtpSent] = useState(false);
  const [otpTimer, setOtpTimer] = useState(0);
  const [canResend, setCanResend] = useState(false);
  const [emailForOtp, setEmailForOtp] = useState('');
  const [emailOtp, setEmailOtp] = useState(['', '', '', '', '', '']);
  const [emailOtpSent, setEmailOtpSent] = useState(false);

  useEffect(() => {
    if (otpTimer > 0) {
      const timer = setTimeout(() => setOtpTimer(otpTimer - 1), 1000);
      return () => clearTimeout(timer);
    } else if (otpTimer === 0 && (otpSent || emailOtpSent)) {
      setCanResend(true);
    }
  }, [otpTimer, otpSent, emailOtpSent]);

  const handleLogin = async () => {
    setError('');
    setLoading(true);
    try {
      if (!loginData.email?.trim()) throw new Error('Email is required');
      if (!loginData.password) throw new Error('Password is required');

      const response = await mongoAuthAPI.login(loginData.email.trim(), loginData.password);
      const data = response?.data;

      if (!data || !data.token) throw new Error('Authentication token not received from server');

      const userRole = String(data.role || '').trim();
      if (!userRole || (userRole !== 'Customer' && userRole !== 'Admin')) throw new Error('Invalid user role');
      if (userRole !== loginRole) throw new Error(`This account is registered as ${userRole}. Please select ${userRole} login.`);

      const userIdFromToken = getUserIdFromToken();
      const finalUserId = userIdFromToken || data.mongoUserId || data.userId || data.id;
      if (!finalUserId) throw new Error('User ID not found. Please contact support.');

      const userData = { ...data, role: userRole, userId: finalUserId, id: finalUserId };
      sessionStorage.setItem('token', data.token);
      sessionStorage.setItem('user', JSON.stringify(userData));

      setUser({
        id: finalUserId,
        userId: finalUserId,
        email: data.email || '',
        role: userRole,
        name: data.fullName || data.name || '',
        mobile: data.mobile || '',
        gender: data.gender || ''
      });

      setCurrentPage(userRole === 'Admin' ? 'admin' : 'products');
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Login failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleRequestOTP = async () => {
    if (mobileNumber.length !== 10) {
      setError('Please enter a valid 10-digit mobile number');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await mongoAuthAPI.requestOtp(mobileNumber);
      if (response.data.success) {
        setOtpSent(true);
        setOtpTimer(300);
        setCanResend(false);
        setTimeout(() => document.getElementById('otp-0')?.focus(), 100);
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to send OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOTP = async () => {
    const otpValue = otp.join('');
    if (otpValue.length !== 6) {
      setError('Please enter complete 6-digit OTP');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await mongoAuthAPI.verifyOtp(mobileNumber, otpValue);
      const data = response.data;
      if (!data.token) throw new Error('No token received');

      sessionStorage.setItem('token', data.token);
      const userIdFromToken = getUserIdFromToken();
      const userData = { ...data, userId: userIdFromToken, id: userIdFromToken };
      sessionStorage.setItem('user', JSON.stringify(userData));

      setUser({
        id: userIdFromToken,
        userId: userIdFromToken,
        email: data.email,
        role: data.role,
        name: data.fullName,
        mobile: data.mobile
      });

      setCurrentPage(data.role === 'Admin' ? 'admin' : 'products');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleRequestEmailOTP = async () => {
    if (!emailForOtp.includes('@')) {
      setError('Please enter a valid email address');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await mongoAuthAPI.requestEmailOtp(emailForOtp);
      if (response.data.success) {
        setEmailOtpSent(true);
        setOtpTimer(300);
        setCanResend(false);
        setTimeout(() => document.getElementById('email-otp-0')?.focus(), 100);
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to send OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyEmailOTP = async () => {
    const otpValue = emailOtp.join('');
    if (otpValue.length !== 6) {
      setError('Please enter complete 6-digit OTP');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await mongoAuthAPI.verifyEmailOtp(emailForOtp, otpValue);
      const data = response.data;
      if (!data.token) throw new Error('No token received');

      sessionStorage.setItem('token', data.token);
      const userIdFromToken = getUserIdFromToken();
      const userData = { ...data, userId: userIdFromToken, id: userIdFromToken };
      sessionStorage.setItem('user', JSON.stringify(userData));

      setUser({
        id: userIdFromToken,
        userId: userIdFromToken,
        email: data.email,
        role: data.role,
        name: data.fullName,
        mobile: data.mobile
      });

      setCurrentPage(data.role === 'Admin' ? 'admin' : 'products');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleOtpChange = (index, value) => {
    if (!/^\d*$/.test(value)) return;
    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);
    if (value && index < 5) document.getElementById(`otp-${index + 1}`)?.focus();
  };

  const handleOtpKeyDown = (index, e) => {
    if (e.key === 'Backspace' && !otp[index] && index > 0) {
      document.getElementById(`otp-${index - 1}`)?.focus();
    }
  };

  const containerVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, x: -20 },
    visible: { opacity: 1, x: 0 }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-600 via-blue-400 to-purple-500 flex items-center justify-center p-6 relative overflow-hidden">
      {/* Animated Background Blobs */}
      <motion.div 
        animate={{ x: [0, 30, 0], y: [0, -30, 0] }}
        transition={{ duration: 8, repeat: Infinity }}
        className="absolute top-0 left-0 w-96 h-96 bg-white/10 rounded-full blur-3xl -translate-x-1/2 -translate-y-1/2"
      />
      <motion.div 
        animate={{ x: [0, -30, 0], y: [0, 30, 0] }}
        transition={{ duration: 8, repeat: Infinity, delay: 1 }}
        className="absolute bottom-0 right-0 w-96 h-96 bg-white/10 rounded-full blur-3xl translate-x-1/2 translate-y-1/2"
      />

      <motion.div 
        className="max-w-xl w-full relative z-10"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        {/* Brand & Intro */}
        <motion.div 
          className="text-center mb-8"
          variants={itemVariants}
        >
          <motion.div 
            whileHover={{ scale: 1.05 }}
            className="inline-flex items-center gap-3 mb-4 bg-white/20 backdrop-blur-md px-6 py-3 rounded-full border border-white/30"
          >
            <motion.div animate={{ rotate: 360 }} transition={{ duration: 20, repeat: Infinity }}>
              <ShoppingBag className="w-8 h-8 text-white" />
            </motion.div>
            <h1 className="text-2xl font-bold text-white">ShopAI</h1>
          </motion.div>
          <p className="text-white/90 text-lg font-medium">Welcome back — sign in to continue</p>
          <p className="text-white/70 text-sm mt-1">Choose a login method that suits you</p>
        </motion.div>

        {/* Card */}
        <motion.div 
          className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-2xl p-8 border border-white/20"
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.5, delay: 0.2 }}
        >
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-3xl font-bold text-gray-900">Sign In</h2>
              <p className="text-sm text-gray-600 mt-2">Access your ShopAI account securely</p>
            </div>
            <motion.button
              onClick={() => setCurrentPage('register')}
              whileHover={{ scale: 1.05 }}
              className="text-sm text-gray-600 hover:text-blue-600 font-semibold transition-colors"
            >
              Create account
            </motion.button>
          </div>

          {/* Error Alert */}
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={error ? { opacity: 1, height: "auto" } : { opacity: 0, height: 0 }}
            transition={{ duration: 0.3 }}
            className="overflow-hidden"
          >
            {error && (
              <motion.div className="bg-red-50 border-l-4 border-red-500 text-red-700 px-5 py-4 rounded-lg mb-6 flex items-start gap-3">
                <div className="w-1 h-1 bg-red-500 rounded-full mt-2.5"></div>
                <p className="text-sm font-medium">{error}</p>
              </motion.div>
            )}
          </motion.div>

          {/* Login Method Tabs */}
          <motion.div 
            className="mb-6"
            variants={itemVariants}
          >
            <label className="block text-sm font-semibold text-gray-700 mb-3">Select Login Method</label>
            <div className="grid grid-cols-3 gap-2 bg-gray-100 rounded-xl p-1.5">
              {[
                { id: 'email', label: 'Password', icon: Lock },
                { id: 'mobile', label: 'Mobile', icon: Smartphone },
                { id: 'emailOtp', label: 'Email', icon: Mail }
              ].map(({ id, label, icon: Icon }) => (
                <motion.button
                  key={id}
                  onClick={() => {
                    setLoginMethod(id);
                    setError('');
                    setOtpSent(false);
                    setEmailOtpSent(false);
                  }}
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                  className={`py-2.5 px-3 rounded-lg font-semibold transition-all duration-300 flex items-center justify-center gap-2 ${
                    loginMethod === id
                      ? 'bg-white shadow-md text-blue-600'
                      : 'text-gray-600 hover:text-gray-900'
                  }`}
                >
                  <Icon className="w-4 h-4" />
                  <span className="hidden sm:inline">{label}</span>
                </motion.button>
              ))}
            </div>
          </motion.div>

          {/* Role Selector */}
          <motion.div 
            className="mb-6"
            variants={itemVariants}
          >
            <label className="block text-sm font-semibold text-gray-700 mb-3">Login As</label>
            <select
              value={loginRole}
              onChange={(e) => setLoginRole(e.target.value)}
              className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-300 bg-white hover:bg-gray-50 cursor-pointer text-gray-700 font-medium"
            >
              <option value="Customer">👤 Customer</option>
              <option value="Admin">🏢 Admin</option>
            </select>
          </motion.div>

          {/* EMAIL + PASSWORD LOGIN */}
          {loginMethod === 'email' && (
            <motion.form
              onSubmit={(e) => { e.preventDefault(); handleLogin(); }}
              className="space-y-5"
              variants={containerVariants}
              initial="hidden"
              animate="visible"
            >
              <motion.div variants={itemVariants}>
                <label className="block text-sm font-semibold text-gray-700 mb-3">Email Address</label>
                <motion.div className="relative group" whileFocus="focus">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5 group-focus-within:text-blue-600 transition-colors" />
                  <input
                    type="email"
                    value={loginData.email}
                    onChange={(e) => setLoginData({ ...loginData, email: e.target.value })}
                    className="w-full pl-12 pr-4 py-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-300 bg-gray-50 focus:bg-white placeholder-gray-400"
                    placeholder="you@example.com"
                    required
                  />
                </motion.div>
              </motion.div>

              <motion.div variants={itemVariants}>
                <label className="block text-sm font-semibold text-gray-700 mb-3">Password</label>
                <div className="relative group">
                  <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5 group-focus-within:text-blue-600 transition-colors" />
                  <input
                    type={showPassword ? 'text' : 'password'}
                    value={loginData.password}
                    onChange={(e) => setLoginData({ ...loginData, password: e.target.value })}
                    className="w-full pl-12 pr-12 py-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-300 bg-gray-50 focus:bg-white placeholder-gray-400"
                    placeholder="••••••••"
                    required
                  />
                  <motion.button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    whileHover={{ scale: 1.1 }}
                    whileTap={{ scale: 0.9 }}
                    className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-blue-600 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                  </motion.button>
                </div>
              </motion.div>

              <motion.button
                type="submit"
                disabled={loading}
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                className="w-full bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white py-3 rounded-xl font-bold text-lg transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg hover:shadow-xl flex items-center justify-center gap-2 group"
              >
                {loading ? (
                  <>
                    <motion.div animate={{ rotate: 360 }} transition={{ duration: 1, repeat: Infinity }} className="w-5 h-5 border-2 border-white border-t-transparent rounded-full"></motion.div>
                    Signing in...
                  </>
                ) : (
                  <>
                    <span>Sign In</span>
                    <motion.div animate={{ x: 5 }} transition={{ repeat: Infinity, repeatType: "reverse" }}>
                      <ArrowRight className="w-5 h-5" />
                    </motion.div>
                  </>
                )}
              </motion.button>
            </motion.form>
          )}

          {/* MOBILE OTP LOGIN */}
          {loginMethod === 'mobile' && (
            <motion.div
              className="space-y-5"
              variants={containerVariants}
              initial="hidden"
              animate="visible"
            >
              {!otpSent ? (
                <>
                  <motion.div variants={itemVariants}>
                    <label className="block text-sm font-semibold text-gray-700 mb-3">Mobile Number</label>
                    <div className="relative group">
                      <Smartphone className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5" />
                      <input
                        type="tel"
                        value={mobileNumber}
                        onChange={(e) => setMobileNumber(e.target.value.replace(/\D/g, '').slice(0, 10))}
                        className="w-full pl-12 pr-4 py-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all"
                        placeholder="9876543210"
                        maxLength={10}
                      />
                    </div>
                    <p className="text-xs text-gray-500 mt-2">📱 We'll send a 6-digit OTP to this number</p>
                  </motion.div>

                  <motion.button
                    onClick={handleRequestOTP}
                    disabled={loading || mobileNumber.length !== 10}
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    className="w-full bg-gradient-to-r from-blue-600 to-blue-700 text-white py-3 rounded-xl font-bold disabled:opacity-50"
                  >
                    {loading ? 'Sending OTP...' : 'Send OTP'}
                  </motion.button>
                </>
              ) : (
                <>
                  <motion.div variants={itemVariants}>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Enter 6-Digit OTP</label>
                    <p className="text-xs text-gray-500 mb-4">
                      ⏱️ Sent to {mobileNumber} • Expires <span className="font-bold text-red-600">{formatTime(otpTimer)}</span>
                    </p>
                    <div className="flex gap-2 justify-center mb-4">
                      {otp.map((digit, idx) => (
                        <motion.input
                          key={idx}
                          id={`otp-${idx}`}
                          type="text"
                          inputMode="numeric"
                          maxLength={1}
                          value={digit}
                          onChange={(e) => handleOtpChange(idx, e.target.value)}
                          onKeyDown={(e) => handleOtpKeyDown(idx, e)}
                          whileFocus={{ scale: 1.1 }}
                          className="w-12 h-12 text-center text-2xl font-bold border-2 border-gray-200 rounded-lg focus:border-blue-500"
                        />
                      ))}
                    </div>
                  </motion.div>

                  <div className="flex gap-3">
                    <motion.button
                      onClick={handleVerifyOTP}
                      disabled={loading || otp.join('').length !== 6}
                      whileHover={{ scale: 1.02 }}
                      className="flex-1 bg-gradient-to-r from-green-600 to-emerald-600 text-white py-3 rounded-xl font-bold disabled:opacity-50"
                    >
                      {loading ? 'Verifying...' : 'Verify & Sign In'}
                    </motion.button>
                    <motion.button
                      onClick={() => {
                        setOtpSent(false);
                        setOtp(['', '', '', '', '', '']);
                      }}
                      whileHover={{ scale: 1.05 }}
                      className="px-6 py-3 border-2 border-gray-200 rounded-xl"
                    >
                      Change
                    </motion.button>
                  </div>
                </>
              )}
            </motion.div>
          )}

          {/* EMAIL OTP LOGIN */}
          {loginMethod === 'emailOtp' && (
            <motion.div
              className="space-y-5"
              variants={containerVariants}
              initial="hidden"
              animate="visible"
            >
              {!emailOtpSent ? (
                <>
                  <motion.div variants={itemVariants}>
                    <label className="block text-sm font-semibold text-gray-700 mb-3">Email Address</label>
                    <div className="relative">
                      <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-400 w-5 h-5" />
                      <input
                        type="email"
                        value={emailForOtp}
                        onChange={(e) => setEmailForOtp(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 border-2 border-gray-200 rounded-xl focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all"
                        placeholder="you@example.com"
                      />
                    </div>
                    <p className="text-xs text-gray-500 mt-2">📧 We'll send a 6-digit code to your email</p>
                  </motion.div>

                  <motion.button
                    onClick={handleRequestEmailOTP}
                    disabled={loading || !emailForOtp.includes('@')}
                    whileHover={{ scale: 1.02 }}
                    className="w-full bg-gradient-to-r from-blue-600 to-blue-700 text-white py-3 rounded-xl font-bold disabled:opacity-50"
                  >
                    {loading ? 'Sending OTP...' : 'Send OTP to Email'}
                  </motion.button>
                </>
              ) : (
                <>
                  <motion.div variants={itemVariants}>
                    <label className="block text-sm font-semibold text-gray-700 mb-2">Enter 6-Digit OTP</label>
                    <div className="flex gap-2 justify-center mb-4">
                      {emailOtp.map((digit, idx) => (
                        <motion.input
                          key={idx}
                          id={`email-otp-${idx}`}
                          type="text"
                          inputMode="numeric"
                          maxLength={1}
                          value={digit}
                          onChange={(e) => {
                            const val = e.target.value;
                            if (!/^\d*$/.test(val)) return;
                            const newOtp = [...emailOtp];
                            newOtp[idx] = val;
                            setEmailOtp(newOtp);
                            if (val && idx < 5) document.getElementById(`email-otp-${idx + 1}`)?.focus();
                          }}
                          whileFocus={{ scale: 1.1 }}
                          className="w-12 h-12 text-center text-2xl font-bold border-2 border-gray-200 rounded-lg focus:border-blue-500"
                        />
                      ))}
                    </div>
                  </motion.div>

                  <div className="flex gap-3">
                    <motion.button
                      onClick={handleVerifyEmailOTP}
                      disabled={loading || emailOtp.join('').length !== 6}
                      whileHover={{ scale: 1.02 }}
                      className="flex-1 bg-gradient-to-r from-green-600 to-emerald-600 text-white py-3 rounded-xl font-bold disabled:opacity-50"
                    >
                      {loading ? 'Verifying...' : 'Verify & Sign In'}
                    </motion.button>
                  </div>
                </>
              )}
            </motion.div>
          )}

          {/* Demo Credentials */}
          <motion.div 
            className="mt-6 bg-white/20 backdrop-blur-md rounded-lg p-4 border border-white/30"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4 }}
          >
            <p className="text-xs text-gray-700 mb-2 font-semibold">Demo Credentials</p>
            <div className="flex gap-2 flex-col sm:flex-row">
              <motion.button
                onClick={() => { 
                  setLoginRole('Admin'); 
                  setLoginData({ email: 'admin@ecommerce.com', password: 'admin123' }); 
                  setLoginMethod('email'); 
                }}
                whileHover={{ scale: 1.02, backgroundColor: "rgba(255,255,255,0.3)" }}
                className="flex-1 text-xs sm:text-sm px-3 py-2 bg-gray-50 rounded-lg hover:bg-white/20 transition-all"
              >
                👤 Admin
              </motion.button>
              <motion.button
                onClick={() => { 
                  setLoginRole('Customer'); 
                  setLoginData({ email: 'customer@test.com', password: 'password123' }); 
                  setLoginMethod('email'); 
                }}
                whileHover={{ scale: 1.02, backgroundColor: "rgba(255,255,255,0.3)" }}
                className="flex-1 text-xs sm:text-sm px-3 py-2 bg-gray-50 rounded-lg hover:bg-white/20 transition-all"
              >
                🛒 Customer
              </motion.button>
            </div>
          </motion.div>

          {/* Back to Home */}
          <motion.div className="mt-5 text-center">
            <motion.button 
              onClick={() => setCurrentPage('home')}
              whileHover={{ x: -5 }}
              className="text-gray-600 text-sm hover:text-gray-800 font-medium"
            >
              ← Back to Home
            </motion.button>
          </motion.div>
        </motion.div>
      </motion.div>
    </div>
  );
};

export default LoginPage;
